103	// NewStatusProbeServiceFromWorkDir constructs a service for status surfaces
104	// without pre-filtering .ddx agent endpoints by /models reachability. The
105	// returned service still probes when ListProviders is called, but unreachable
106	// configured endpoints remain present in the result as unreachable rows.
107	func NewStatusProbeServiceFromWorkDir(workDir string) (agentlib.DdxAgent, error) {
108		opts := agentlib.ServiceOptions{
109			ConfigPath: filepath.Join(workDir, "config.yaml"),
110		}
111		sc, err := serviceConfigFromDDxEndpointsNoFilter(workDir)
112		if err != nil {
113			return nil, err
114		}
115		if sc != nil {
116			opts.ServiceConfig = sc
117		}
118		return agentlib.New(opts)
119	}
