128	func serviceConfigFromDDxEndpoints(workDir string) (agentlib.ServiceConfig, error) {
129		cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
130		if err != nil {
131			return nil, err
132		}
133		if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
134			return nil, nil
135		}
136		return newEndpointServiceConfigWithoutLiveFilter(cfg.Agent.Endpoints, workDir)
137	}
