150	// ConfiguredProviderSnapshots returns endpoint-provider rows from .ddx config
151	// without probing their /models endpoints. It is used by UI surfaces that must
152	// first-paint from last-known or configured state and refresh live probes
153	// asynchronously.
154	func ConfiguredProviderSnapshots(workDir string) ([]agentlib.ProviderInfo, bool, error) {
155		cfg, err := ddxconfig.LoadWithWorkingDir(workDir)
156		if err != nil {
157			return nil, false, err
158		}
159		if cfg.Agent == nil || len(cfg.Agent.Endpoints) == 0 {
160			return nil, false, nil
161		}
162		out := make([]agentlib.ProviderInfo, 0, len(cfg.Agent.Endpoints))
163		for i, endpoint := range cfg.Agent.Endpoints {
164			name, entry, err := endpointProviderEntry(endpoint, i)
165			if err != nil {
166				return nil, true, err
167			}
168			out = append(out, agentlib.ProviderInfo{
169				Name:         name,
170				Type:         strings.ToLower(strings.TrimSpace(entry.Type)),
171				BaseURL:      entry.BaseURL,
172				Endpoints:    append([]agentlib.ServiceProviderEndpoint(nil), entry.Endpoints...),
173				Status:       "unknown",
174				DefaultModel: entry.Model,
175				IsDefault:    i == 0,
176			})
177		}
178		return out, true, nil
179	}
