181	func newEndpointServiceConfigWithoutLiveFilter(endpoints []ddxconfig.AgentEndpoint, workDir string) (*endpointServiceConfig, error) {
182		sc := &endpointServiceConfig{
183			providers: make(map[string]agentlib.ServiceProviderEntry),
184			workDir:   workDir,
185		}
186		for i, endpoint := range endpoints {
187			name, entry, err := endpointProviderEntry(endpoint, i)
188			if err != nil {
189				return nil, err
190			}
191			sc.providers[name] = entry
192			sc.names = append(sc.names, name)
193			if sc.defaultName == "" {
194				sc.defaultName = name
195			}
196		}
197		return sc, nil
198	}
