200	func endpointProviderEntry(endpoint ddxconfig.AgentEndpoint, index int) (string, agentlib.ServiceProviderEntry, error) {
201		providerType := strings.ToLower(strings.TrimSpace(endpoint.Type))
202		baseURL := strings.TrimSpace(endpoint.BaseURL)
203		if baseURL == "" {
204			if endpoint.Host == "" || endpoint.Port == 0 {
205				return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: base_url or host+port is required", index)
206			}
207			baseURL = fmt.Sprintf("http://%s:%d/v1", endpoint.Host, endpoint.Port)
208		}
209		if providerType == "" {
210			providerType = inferEndpointProviderType(baseURL, endpoint.Port)
211		}
212		if providerType == "" {
213			return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: type is required when it cannot be inferred", index)
214		}
215	
216		name := endpointProviderName(providerType, baseURL, endpoint, index)
217		return name, agentlib.ServiceProviderEntry{
218			Type:    providerType,
219			BaseURL: baseURL,
220			APIKey:  endpoint.APIKey,
221		}, nil
222	}
