224	func inferEndpointProviderType(baseURL string, port int) string {
225		low := strings.ToLower(baseURL)
226		switch {
227		case strings.Contains(low, "openrouter.ai"):
228			return "openrouter"
229		case strings.Contains(low, "openai.com"):
230			return "openai"
231		case strings.Contains(low, ":1235") || port == 1235:
232			return "omlx"
233		case strings.Contains(low, ":11434") || port == 11434:
234			return "ollama"
235		case strings.Contains(low, ":1234") || port == 1234:
236			return "lmstudio"
237		default:
238			return ""
239		}
240	}
